/* Suggested markup: <div class="uiwiki-saving-state-chip" tabindex="0"><span>Saving State Chip</span></div> */
.uiwiki-saving-state-chip {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-saving-state-chip > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: saving_state_chip 1.8s ease-in-out infinite alternate;
}
.uiwiki-saving-state-chip:hover,
.uiwiki-saving-state-chip:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes saving_state_chip {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-saving-state-chip, .uiwiki-saving-state-chip > span { animation: none; transition: none; }
}
